/**
 * Detecta delimitador de forma robusta, priorizando a contagem de colunas esperada se fornecida.
 */
const detectDelimiter = (line: string, expectedColumns?: number): string => {
    const candidates = [';', ',', '\t', '|'];

    // Se temos uma expectativa de colunas (vinda do Modelo), testamos qual delimitador atende
    if (expectedColumns && expectedColumns > 1) {
        for (const char of candidates) {
            if (line.split(char).length === expectedColumns) {
                return char;
            }
        }
    }

    // Heurística padrão se não houver expectativa ou falhar
    if (line.includes('\t')) return '\t';
    if (line.includes(';') && !line.includes(',')) return ';'; // Prioridade Excel BR
    if (line.includes('|')) return '|';

    // Se tem vírgula e parece decimal (100,00), prefere ponto-e-vírgula se existir, senão vírgula
    if (line.includes(',')) {
        if (/\d,\d/.test(line) && line.includes(';')) return ';';
        return ',';
    }
    return ';'; // Fallback
};

export const generateFingerprint = (content: string): FileModel['fingerprint'] | null => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length === 0) return null;

    const delimiter = detectDelimiter(lines[0]);
    const header = lines[0];
    const cells = header.split(delimiter);

    const headerHash = header.split('').reduce((a, b) => { 
        a = ((a << 5) - a) + b.charCodeAt(0); 
        return a & a; 
    }, 0).toString(36);

    const dataRows = lines.slice(1, 10);
    let topology = "";
    if (dataRows.length > 0) {
        const sampleRow = dataRows.find(r => r.split(delimiter).length === cells.length) || dataRows[0];
        topology = sampleRow.split(delimiter).map(c => {
            const clean = c.trim().replace(/[R$\s]/g, '').replace(',', '.');
            return isNaN(parseFloat(clean)) ? 'S' : 'N';
        }).join(',');
    }

    return { columnCount: cells.length, delimiter, headerHash, dataTopology: topology };
};

export const findMatchingModel = (content: string, models: FileModel[]): FileModel | null => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length === 0) return null;

    // Gera fingerprint "na hora"
    const current = generateFingerprint(content);
    if (!current) return null;

    // Também gera hash simples da string do cabeçalho para comparação exata
    const rawHeader = lines[0].trim();

    return models.find(m => {
        if (!m.is_active) return false;

        // 1. Verifica Hash Exato de Cabeçalho (Mais confiável)
        // Precisamos reconstruir o header esperado baseando no delimitador do modelo
        // Mas como não temos o arquivo original do modelo, usamos o hash salvo
        if (m.fingerprint.headerHash === current.headerHash) return true;

        // 2. Verifica contagem de colunas + topologia
        if (m.fingerprint.columnCount === current.columnCount) {
             // Se o cabeçalho mudou mas a estrutura de dados (Topologia N,S,N) é igual, aceita
             if (m.fingerprint.dataTopology === current.dataTopology) return true;
        }

        return false;
    }) || null;
};

export const isModelSafeToApply = (content: string, model: FileModel): { safe: boolean; reason?: string } => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length === 0) return { safe: false, reason: "Arquivo vazio" };

    // Tenta detectar delimitador forçando a contagem de colunas do modelo
    const delimiter = detectDelimiter(lines[0], model.fingerprint.columnCount);
    const cols = lines[0].split(delimiter).length;

    if (cols !== model.fingerprint.columnCount) {
        return { safe: false, reason: `Divergência de colunas: esperado ${model.fingerprint.columnCount}, detectado ${cols}` };
    }

    return { safe: true };
};

