        return null;
    }

    let cleanedName = NameResolver.clean(rawDesc, userKeywords);
    if (!cleanedName || cleanedName.trim().length === 0) {
        cleanedName = rawDesc.trim(); 
        if (!cleanedName) cleanedName = "Sem descrição"; 
    }

    return {
        id: `tx-norm-${index}-${Date.now()}`,
