export const parseWithModel = (content: string, model: FileModel, userKeywords: string[] = []): Transaction[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    const { mapping, parsingRules } = model;
    const anchorYear = DateResolver.discoverAnchorYear(content);

    // DELIMITADOR DINÂMICO INTELIGENTE:
    // Usa a contagem de colunas salva no modelo para forçar a escolha do delimitador correto.
    // Isso corrige casos onde um CSV salvo com ';' é aberto como ',' ou vice-versa.
    const currentDelimiter = detectDelimiter(lines[0] || '', model.fingerprint.columnCount);

    const savedKeywords = parsingRules?.ignoredKeywords || [];
    const effectiveKeywords = Array.from(new Set([...savedKeywords, ...userKeywords]));

    const dataLines = lines.slice(mapping.skipRowsStart, mapping.skipRowsEnd ? lines.length - mapping.skipRowsEnd : undefined);

    return dataLines.map((line, i) => {
        const upperLine = line.toUpperCase();
        if (parsingRules?.rowFilters?.some(f => upperLine.includes(f.toUpperCase()))) return null;

        const cells = line.split(currentDelimiter).map(c => c.trim().replace(/^["']|["']$/g, ''));

        // Verifica se a linha tem colunas suficientes para o mapeamento
        const maxIndexNeeded = Math.max(mapping.dateColumnIndex, mapping.descriptionColumnIndex, mapping.amountColumnIndex);
        if (cells.length <= maxIndexNeeded) return null;

        const rawDate = cells[mapping.dateColumnIndex] || '';
        const rawDesc = cells[mapping.descriptionColumnIndex] || '';
        const rawAmount = cells[mapping.amountColumnIndex] || '';
        const rawType = mapping.typeColumnIndex !== undefined && mapping.typeColumnIndex !== null ? cells[mapping.typeColumnIndex] : undefined;

        return finalizeTransaction(rawDate, rawDesc, rawAmount, rawType, anchorYear, i, effectiveKeywords);
    }).filter((t): t is Transaction => t !== null);
};

export const parseBankStatement = (content: string, customIgnoreKeywords: string[] = [], contributionKeywords: string[] = DEFAULT_CONTRIBUTION_KEYWORDS): Transaction[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 1) return [];

    const delimiter = detectDelimiter(lines[0]);
    const parsedRows = lines.map(l => l.split(delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));
    const anchorYear = DateResolver.discoverAnchorYear(content);

    const dateIdx = DateResolver.identifyDateColumn(parsedRows);
    const amountIdx = AmountResolver.identifyAmountColumn(parsedRows, [dateIdx]);
    const nameIdx = NameResolver.identifyNameColumn(parsedRows, [dateIdx, amountIdx]);
    const typeIdx = identifyTypeColumn(parsedRows, contributionKeywords);

    return parsedRows.map((row, i) => {
        const rawType = typeIdx !== -1 ? row[typeIdx] : undefined;
        const rawDate = dateIdx !== -1 ? (row[dateIdx] || '') : ''; 
        const safeDate = rawDate || row[0];
        const safeName = row[nameIdx !== -1 ? nameIdx : 1] || '';
        const safeAmount = row[amountIdx !== -1 ? amountIdx : 2] || '0';

        return finalizeTransaction(safeDate, safeName, safeAmount, rawType, anchorYear, i, customIgnoreKeywords);
    }).filter((t): t is Transaction => t !== null);
};

export const normalizeString = (str: string, ignoreKeywords: string[] = []): string => {
    if (!str) return '';
    let cleaned = NameResolver.clean(str, ignoreKeywords);
    if (!cleaned || cleaned.trim().length === 0) cleaned = str;
    return NameResolver.normalize(cleaned).toLowerCase();
};

export const calculateNameSimilarity = (description: string, contributor: Contributor, ignoreKeywords: string[] = []): number => {
    const txNorm = normalizeString(description, ignoreKeywords);
    const contribNorm = contributor.normalizedName || normalizeString(contributor.name, ignoreKeywords);

    if (!txNorm || !contribNorm) return 0;

    const txTokens = txNorm.split(/\s+/).filter(t => t.length > 0);
    const contribTokens = contribNorm.split(/\s+/).filter(t => t.length > 0);

    if (txTokens.length === 0 || contribTokens.length === 0) return 0;

    const txSet = new Set(txTokens);
    const contribSet = new Set(contribTokens);
    const intersection = [...txSet].filter(w => contribSet.has(w)).length;
    return (2 * intersection) / (txSet.size + contribSet.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: any[],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: any[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    const allContributors = contributorFiles.flatMap(file => 
        file.contributors.map((c: any) => ({ ...c, church: file.church }))
    );

    const finalResults: MatchResult[] = [];

    transactions.forEach(tx => {
        if (NameResolver.isControlRow(tx.description)) return;

        const txDescNormalized = normalizeString(tx.description, customIgnoreKeywords);

        const learned = learnedAssociations.find(la => la.normalizedDescription === txDescNormalized);
        if (learned) {
            const matchedContrib = allContributors.find(c => 
                (normalizeString(c.name, customIgnoreKeywords) === learned.contributorNormalizedName) && 
                (c.church.id === learned.churchId)
            );
            if (matchedContrib) {
                finalResults.push({ 
                    transaction: tx, contributor: matchedContrib, status: 'IDENTIFICADO', 
                    church: matchedContrib.church, matchMethod: 'LEARNED', similarity: 100, 
                    contributorAmount: matchedContrib.amount,
                    contributionType: matchedContrib.contributionType || tx.contributionType
                });
                return;
            }
        }

        let bestMatch: any = null;
        let highestScore = 0;

        allContributors.forEach(contrib => {
            if (options.dayTolerance !== undefined && contrib.date && tx.date) {
                const tDate = parseDate(tx.date);
                const cDate = parseDate(contrib.date);
                if (tDate && cDate) {
                    const diffDays = Math.ceil(Math.abs(tDate.getTime() - cDate.getTime()) / (1000 * 3600 * 24));
                    if (diffDays > options.dayTolerance) return;
                }
            }

            const score = calculateNameSimilarity(tx.description, contrib, customIgnoreKeywords);
            if (score >= options.similarityThreshold && score > highestScore) {
                highestScore = score;
                bestMatch = contrib;
            }
        });

        if (bestMatch) {
            finalResults.push({ 
                transaction: tx, contributor: bestMatch, status: 'IDENTIFICADO', 
                church: bestMatch.church, similarity: highestScore, 
                matchMethod: 'AUTOMATIC', contributorAmount: bestMatch.amount,
                contributionType: bestMatch.contributionType || tx.contributionType
            });
        } else {
            finalResults.push({ 
                transaction: tx, contributor: null, status: 'NÃO IDENTIFICADO', 
                church: PLACEHOLDER_CHURCH,
                contributionType: tx.contributionType
            });
        }
    });

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): Record<string, MatchResult[]> => {
    const grouped: Record<string, MatchResult[]> = {};
    results.forEach(r => {
        const key = r.church?.id || 'unidentified';
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

export const parseDate = (dateString: string): Date | null => {
    if (!dateString) return null;
    const clean = dateString.trim().replace(/\//g, '-');
    if (/^\d{4}-\d{2}-\d{2}$/.test(clean)) return new Date(clean);

    const parts = clean.split('-');
    if (parts.length === 3) {
        if (parts[0].length === 4) return new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        else return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    }
    return null;
};

export const parseContributors = (content: string, ignoreKeywords: string[] = [], contributionKeywords: string[] = DEFAULT_CONTRIBUTION_KEYWORDS): Contributor[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 1) return [];

    const delimiter = detectDelimiter(lines[0]);
    const parsedRows = lines.map(l => l.split(delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));
    const anchorYear = DateResolver.discoverAnchorYear(content);

    const dateIdx = DateResolver.identifyDateColumn(parsedRows);
    const amountIdx = AmountResolver.identifyAmountColumn(parsedRows, [dateIdx]);
    const nameIdx = NameResolver.identifyNameColumn(parsedRows, [dateIdx, amountIdx]);
    const typeIdx = identifyTypeColumn(parsedRows, contributionKeywords);

    return parsedRows.map((row, i): Contributor | null => {
        const rawDate = dateIdx !== -1 ? (row[dateIdx] || '') : '';
        const isoDate = rawDate ? DateResolver.resolveToISO(rawDate, anchorYear) : undefined;

        const rawName = nameIdx !== -1 ? (row[nameIdx] || '') : (row[0] || '');
        const rawAmount = amountIdx !== -1 ? (row[amountIdx] || '') : '0.00';
        const rawType = typeIdx !== -1 ? row[typeIdx] : undefined;

        const standardizedAmountStr = AmountResolver.clean(rawAmount);
        const numericAmount = parseFloat(standardizedAmountStr);

        let cleanedName = NameResolver.clean(rawName, ignoreKeywords);
        if (!cleanedName || cleanedName.trim().length === 0) cleanedName = rawName.trim();

        if (!cleanedName || isNaN(numericAmount)) {
            return null;
        }

        return {
            name: cleanedName,
            cleanedName: cleanedName,
            normalizedName: normalizeString(rawName, ignoreKeywords),
            amount: numericAmount,
            date: isoDate,
            originalAmount: rawAmount,
            contributionType: rawType?.trim().toUpperCase()
        };
    }).filter((c): c is Contributor => c !== null);
};

export const cleanTransactionDescriptionForDisplay = (description: string, ignoreKeywords: string[] = []): string => {
    const cleaned = NameResolver.clean(description, ignoreKeywords);
    if (!cleaned || cleaned.trim().length === 0) return description;
    return cleaned;
};

export const formatIncomeDescription = (description: string, ignoreKeywords: string[] = []): string => {
    return cleanTransactionDescriptionForDisplay(description, ignoreKeywords);
};

export const formatExpenseDescription = (description: string): string => {
    return NameResolver.clean(description);
};

export const filterTransactionByUniversalQuery = (tx: Transaction, query: string): boolean => {
    if (!query || !query.trim()) return true;
    const terms = query.toLowerCase().split(/\s+/).filter(t => t.length > 0);
    const dateStr = tx.date.toLowerCase();
    const descStr = (tx.cleanedDescription || tx.description || '').toLowerCase();
    const typeStr = (tx.contributionType || '').toLowerCase();
    const amountStr = tx.amount.toFixed(2).replace('.', ',');
    const amountStrDot = tx.amount.toFixed(2);

    return terms.every(term => 
        dateStr.includes(term) || 
        descStr.includes(term) || 
        typeStr.includes(term) ||
        amountStr.includes(term) || 
        amountStrDot.includes(term)
    );
};

export const filterByUniversalQuery = (result: MatchResult, query: string): boolean => {
    if (!query || !query.trim()) return true;
    const terms = query.toLowerCase().split(/\s+/).filter(t => t.length > 0);

    const tx = result.transaction;
    const dateStr = (result.contributor?.date || tx.date).toLowerCase();
    const descStr = (tx.cleanedDescription || tx.description || '').toLowerCase();
    const contribName = (result.contributor?.name || '').toLowerCase();
    const churchName = (result.church?.name || '').toLowerCase();
    const typeStr = (result.contributionType || '').toLowerCase();

    const amount = result.contributorAmount ?? tx.amount;
    const amountStr = amount.toFixed(2).replace('.', ',');
    const amountStrDot = amount.toFixed(2);

    return terms.every(term => 
        dateStr.includes(term) || 
        descStr.includes(term) || 
        contribName.includes(term) || 
        churchName.includes(term) || 
        typeStr.includes(term) ||
        amountStr.includes(term) || 
        amountStrDot.includes(term)
    );
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    findMatchingModel,
    PLACEHOLDER_CHURCH,
    parseWithModel,
    isModelSafeToApply,
    normalizeString
} from '../services/processingService';

interface UseReconciliationProps {
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>('identificapix-statement-v7', null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>('identificapix-contributors-v6', [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>('identificapix-results-v6', [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>('identificapix-report-preview-v6', null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>('identificapix-has-session-v6', false, false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            const matchedModel = findMatchingModel(content, fileModels);

            if (matchedModel) {
                const safety = isModelSafeToApply(content, matchedModel);
                if (safety.safe) {
                    const transactions = parseWithModel(content, matchedModel, customIgnoreKeywords);

                    if (transactions.length === 0) {
                        showToast("Nenhuma transação encontrada com o modelo atual. Abrindo laboratório.", "error");
                        setPendingTraining({ content, fileName, type: 'statement', entityId: bankId, rawFile });
                    } else {
                        setBankStatementFile({ 
                            bankId, 
                            content, 
                            fileName, 
                            rawFile,
                            processedTransactions: transactions 
                        });
                        showToast(`Extrato processado (${transactions.length} registros).`, 'success');
                    }
                } else {
                    setPendingTraining({ content, fileName, type: 'statement', entityId: bankId, rawFile });
                    showToast("Layout divergente do modelo. Ajuste necessário.", "error");
                }
            } else {
                setPendingTraining({ content, fileName, type: 'statement', entityId: bankId, rawFile });
                showToast("Novo layout detectado. Abrindo laboratório...", "success");
            }
        } catch (e) {
            showToast("Erro ao ler o arquivo.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, setBankStatementFile, showToast, setIsLoading, customIgnoreKeywords]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            const matchedModel = findMatchingModel(content, fileModels);

            if (matchedModel) {
                const safety = isModelSafeToApply(content, matchedModel);
                if (safety.safe) {
                    const transactions = parseWithModel(content, matchedModel, customIgnoreKeywords);
                    const contributors: Contributor[] = transactions.map(t => ({
                        name: t.description,
                        cleanedName: t.cleanedDescription,
                        normalizedName: normalizeString(t.description, customIgnoreKeywords),
                        amount: t.amount,
                        date: t.date,
                        originalAmount: t.originalAmount,
                        contributionType: t.contributionType
                    }));

                    setContributorFiles(prev => {
                        const other = prev.filter(f => f.churchId !== churchId);
                        return [...other, { churchId, content, fileName, contributors }];
                    });
                    showToast(`Lista padronizada (${contributors.length} registros).`, 'success');
                } else {
                    setPendingTraining({ content, fileName, type: 'contributor', entityId: churchId, rawFile });
                    showToast("Layout divergente do modelo. Ajuste necessário.", "error");
                }
            } else {
                setPendingTraining({ content, fileName, type: 'contributor', entityId: churchId, rawFile });
                showToast("Novo layout detectado. Abrindo laboratório...", "success");
            }
        } catch (e) {
            showToast("Erro ao ler o arquivo.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, customIgnoreKeywords, setContributorFiles, showToast, setIsLoading]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo com sucesso!", "success");
        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, customIgnoreKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes processada.", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, customIgnoreKeywords, setBankStatementFile, setContributorFiles, showToast]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    const handleCompare = useCallback(async () => {
        if (!bankStatementFile) return;
        setIsLoading(true);

        try {
            // 1. Garante que temos as transações do extrato
            let transactions: Transaction[] = bankStatementFile.processedTransactions || [];

            // FALLBACK AGRESSIVO: Se não tiver transações (ex: cache antigo ou falha no upload), reprocessa AGORA.
            if (transactions.length === 0) {
                console.warn("Transações do extrato vazias. Tentando reprocessar com modelos atuais...");
                const stmtModel = findMatchingModel(bankStatementFile.content, fileModels);
                if (stmtModel) {
                    transactions = parseWithModel(bankStatementFile.content, stmtModel, customIgnoreKeywords);
                    // Atualiza o estado para não precisar reprocessar depois
                    setBankStatementFile(prev => prev ? { ...prev, processedTransactions: transactions } : null);
                } else {
                    throw new Error("Extrato sem dados processados. Configure o modelo no Laboratório.");
                }
            }

            if (transactions.length === 0) {
                throw new Error("O extrato parece estar vazio ou o modelo não capturou nenhuma linha.");
            }

            // Filtros de Tipo
            if (comparisonType === 'income') transactions = transactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') transactions = transactions.filter(t => t.amount < 0);

            // 2. Prepara os dados dos contribuintes (também com FALLBACK AGRESSIVO)
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;
                let contributors = cf.contributors || [];

                // Se a lista estiver vazia, tenta reprocessar com o modelo salvo AGORA
                if (contributors.length === 0) {
                    console.warn(`Lista da igreja ${church.name} vazia. Tentando reprocessar...`);
                    const model = findMatchingModel(cf.content, fileModels);
                    if (model) {
                        const txs = parseWithModel(cf.content, model, customIgnoreKeywords);
                        contributors = txs.map(t => ({
                            name: t.description,
                            cleanedName: t.cleanedDescription,
                            normalizedName: normalizeString(t.description, customIgnoreKeywords),
                            amount: t.amount,
                            date: t.date,
                            originalAmount: t.originalAmount,
                            contributionType: t.contributionType
                        }));
                    }
                }

                return {
                    church,
                    contributors
                };
            });

            // 3. Executa o Matching
            const results = matchTransactions(transactions, contributorData, { similarityThreshold: similarityLevel, dayTolerance }, learnedAssociations, churches, customIgnoreKeywords);

            setMatchResults(results);
            setReportPreviewData({
                income: groupResultsByChurch(results.filter(r => r.transaction.amount > 0)),
                expenses: { 'all_expenses_group': results.filter(r => r.transaction.amount < 0) }
            });
            setHasActiveSession(true);
            setActiveView('reports');
            showToast("Conciliação finalizada!", 'success');
        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, contributorFiles, churches, fileModels, similarityLevel, dayTolerance, customIgnoreKeywords, contributionKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses') => {
        setMatchResults(prev => prev.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r));
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            Object.keys(targetGroup).forEach(key => {
                targetGroup[key] = targetGroup[key].map((r: MatchResult) => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
            });

            if (reportType === 'income') {
                const currentChurchId = updatedRow.church.id || 'unidentified';
                Object.keys(newPreview.income).forEach(key => {
                    newPreview.income[key] = newPreview.income[key].filter((r: MatchResult) => r.transaction.id !== updatedRow.transaction.id);
                });
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };
        updateReportData(updatedResult, 'income');
        closeManualMatchModal();
        showToast("Associação manual confirmada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transactionId: string) => {
        setLoadingAiId(transactionId);
        setTimeout(() => {
            setAiSuggestion({ id: transactionId, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile,
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, 
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze
    ]);
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    findMatchingModel,
    PLACEHOLDER_CHURCH,
    parseWithModel,
    isModelSafeToApply,
    normalizeString,
    parseBankStatement,
    parseContributors
} from '../services/processingService';

interface UseReconciliationProps {
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>('identificapix-statement-v7', null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>('identificapix-contributors-v6', [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>('identificapix-results-v6', [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>('identificapix-report-preview-v6', null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>('identificapix-has-session-v6', false, false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // Tenta processar imediatamente, mas não bloqueia se falhar, pois o handleCompare fará o definitivo
            const matchedModel = findMatchingModel(content, fileModels);
            let transactions: Transaction[] = [];

            if (matchedModel && isModelSafeToApply(content, matchedModel).safe) {
                transactions = parseWithModel(content, matchedModel, customIgnoreKeywords);
            } else {
                // Se não tem modelo, tenta um parse genérico só para preencher a UI
                transactions = parseBankStatement(content, customIgnoreKeywords, contributionKeywords);
            }

            // Se for um arquivo totalmente novo e desconhecido, sugere o laboratório
            if (!matchedModel && transactions.length === 0) {
                 setPendingTraining({ content, fileName, type: 'statement', entityId: bankId, rawFile });
                 showToast("Novo layout detectado. Abrindo laboratório...", "success");
            } else {
                setBankStatementFile({ 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile,
                    processedTransactions: transactions 
                });
                showToast(`Arquivo carregado.`, 'success');
            }
        } catch (e) {
            showToast("Erro ao ler o arquivo.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, setBankStatementFile, showToast, setIsLoading, customIgnoreKeywords, contributionKeywords]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            const matchedModel = findMatchingModel(content, fileModels);
            let contributors: Contributor[] = [];

            if (matchedModel && isModelSafeToApply(content, matchedModel).safe) {
                const transactions = parseWithModel(content, matchedModel, customIgnoreKeywords);
                contributors = transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, customIgnoreKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));
            } else {
                contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
            }

            if (!matchedModel && contributors.length === 0) {
                setPendingTraining({ content, fileName, type: 'contributor', entityId: churchId, rawFile });
                showToast("Novo layout detectado. Abrindo laboratório...", "success");
            } else {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });
                showToast(`Arquivo carregado.`, 'success');
            }
        } catch (e) {
            showToast("Erro ao ler o arquivo.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, customIgnoreKeywords, contributionKeywords, setContributorFiles, showToast, setIsLoading]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo com sucesso!", "success");
        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, customIgnoreKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes processada.", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, customIgnoreKeywords, setBankStatementFile, setContributorFiles, showToast]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile) return;
        setIsLoading(true);

        try {
            // 1. REPROCESSAMENTO AUTOMÁTICO DO EXTRATO
            // Busca o modelo mais atualizado para o conteúdo do arquivo
            const stmtModel = findMatchingModel(bankStatementFile.content, fileModels);
            let activeTransactions: Transaction[] = [];

            if (stmtModel) {
                // Se achou modelo, aplica a transformação silenciosa
                console.log(`Aplicando modelo salvo '${stmtModel.name}' ao extrato...`);
                activeTransactions = parseWithModel(bankStatementFile.content, stmtModel, customIgnoreKeywords);
            } else {
                // Fallback: Tenta usar o que já estava em memória ou parse genérico
                console.warn("Nenhum modelo encontrado para o extrato. Usando parser genérico.");
                activeTransactions = bankStatementFile.processedTransactions && bankStatementFile.processedTransactions.length > 0
                    ? bankStatementFile.processedTransactions
                    : parseBankStatement(bankStatementFile.content, customIgnoreKeywords, contributionKeywords);
            }

            if (activeTransactions.length === 0) {
                throw new Error("O extrato não gerou transações válidas. Verifique o modelo no Laboratório.");
            }

            // Atualiza o estado global para refletir o processamento mais recente
            setBankStatementFile(prev => prev ? { ...prev, processedTransactions: activeTransactions } : null);

            // Filtros de Tipo (Income/Expenses)
            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. REPROCESSAMENTO AUTOMÁTICO DAS LISTAS DE CONTRIBUINTES
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;

                // Busca modelo atualizado para esta lista
                const listModel = findMatchingModel(cf.content, fileModels);
                let currentContributors: Contributor[] = [];

                if (listModel) {
                    console.log(`Aplicando modelo salvo '${listModel.name}' à lista de ${church.name}...`);
                    const txs = parseWithModel(cf.content, listModel, customIgnoreKeywords);
                    currentContributors = txs.map(t => ({
                        name: t.description,
                        cleanedName: t.cleanedDescription,
                        normalizedName: normalizeString(t.description, customIgnoreKeywords),
                        amount: t.amount,
                        date: t.date,
                        originalAmount: t.originalAmount,
                        contributionType: t.contributionType
                    }));
                } else {
                    // Fallback
                    currentContributors = cf.contributors || parseContributors(cf.content, customIgnoreKeywords, contributionKeywords);
                }

                return {
                    church,
                    contributors: currentContributors
                };
            });

            // 3. EXECUTAR O MATCHING COM DADOS FRESCOS
            const results = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                customIgnoreKeywords
            );

            setMatchResults(results);
            setReportPreviewData({
                income: groupResultsByChurch(results.filter(r => r.transaction.amount > 0)),
                expenses: { 'all_expenses_group': results.filter(r => r.transaction.amount < 0) }
            });
            setHasActiveSession(true);
            setActiveView('reports');
            showToast("Conciliação finalizada e modelos aplicados!", 'success');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, contributorFiles, churches, fileModels, similarityLevel, dayTolerance, customIgnoreKeywords, contributionKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses') => {
        setMatchResults(prev => prev.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r));
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            Object.keys(targetGroup).forEach(key => {
                targetGroup[key] = targetGroup[key].map((r: MatchResult) => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
            });

            if (reportType === 'income') {
                const currentChurchId = updatedRow.church.id || 'unidentified';
                Object.keys(newPreview.income).forEach(key => {
                    newPreview.income[key] = newPreview.income[key].filter((r: MatchResult) => r.transaction.id !== updatedRow.transaction.id);
                });
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };
        updateReportData(updatedResult, 'income');
        closeManualMatchModal();
        showToast("Associação manual confirmada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transactionId: string) => {
        setLoadingAiId(transactionId);
        setTimeout(() => {
            setAiSuggestion({ id: transactionId, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile,
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, 
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze
    ]);
};

import { Transaction, Contributor, MatchResult, Church, FileModel } from '../types';
import { NameResolver } from '../core/processors/NameResolver';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { RowValidator } from '../core/processors/RowValidator';

export const PLACEHOLDER_CHURCH: Church = {
    id: 'unidentified',
    name: '---', 
    address: '',
    logoUrl: '',
    pastor: '',
};

export const DEFAULT_CONTRIBUTION_KEYWORDS = [
    'DÍZIMO', 'DÍZIMOS', 'OFERTA', 'OFERTAS', 'COLETA', 'COLETAS', 'MISSÃO', 'MISSÕES', 'VOTOS', 'CAMPANHA'
];

/**
 * Extrai as primeiras 20 linhas de um arquivo para fins de snippet/preview.
 */
export const extractSnippet = (content: string): string => {
    if (!content) return '';
    return content.split(/\r?\n/).slice(0, 20).join('\n');
};

/**
 * Identifica a coluna de TIPO analisando palavras-chave.
 */
const identifyTypeColumn = (rows: string[][], contributionKeywords: string[]): number => {
    const sample = rows.slice(0, 100);
    if (sample.length === 0) return -1;

    const scores = new Array(rows[0]?.length || 0).fill(0);
    const keywords = contributionKeywords.map(k => k.toUpperCase().trim());

    sample.forEach(row => {
        row.forEach((cell, index) => {
            const val = String(cell || '').toUpperCase().trim();
            if (keywords.some(k => val === k || val.includes(k))) {
                scores[index] += 1;
            }
        });
    });

    const maxScore = Math.max(...scores);
    return maxScore > (sample.length * 0.10) ? scores.indexOf(maxScore) : -1;
};

/**
 * Detecta delimitador de forma robusta, priorizando a contagem de colunas esperada se fornecida.
 */
const detectDelimiter = (line: string, expectedColumns?: number): string => {
    const candidates = [';', ',', '\t', '|'];

    // Se temos uma expectativa de colunas (vinda do Modelo), testamos qual delimitador atende
    if (expectedColumns && expectedColumns > 1) {
        for (const char of candidates) {
            if (line.split(char).length === expectedColumns) {
                return char;
            }
        }
    }

    // Heurística padrão se não houver expectativa ou falhar
    if (line.includes('\t')) return '\t';
    if (line.includes(';') && !line.includes(',')) return ';'; // Prioridade Excel BR
    if (line.includes('|')) return '|';

    // Se tem vírgula e parece decimal (100,00), prefere ponto-e-vírgula se existir, senão vírgula
    if (line.includes(',')) {
        if (/\d,\d/.test(line) && line.includes(';')) return ';';
        return ',';
    }
    return ';'; // Fallback
};

export const generateFingerprint = (content: string): FileModel['fingerprint'] | null => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length === 0) return null;

    const delimiter = detectDelimiter(lines[0]);
    const header = lines[0];
    const cells = header.split(delimiter);

    const headerHash = header.split('').reduce((a, b) => { 
        a = ((a << 5) - a) + b.charCodeAt(0); 
        return a & a; 
    }, 0).toString(36);

    const dataRows = lines.slice(1, 10);
    let topology = "";
    if (dataRows.length > 0) {
        const sampleRow = dataRows.find(r => r.split(delimiter).length === cells.length) || dataRows[0];
        topology = sampleRow.split(delimiter).map(c => {
            const clean = c.trim().replace(/[R$\s]/g, '').replace(',', '.');
            return isNaN(parseFloat(clean)) ? 'S' : 'N';
        }).join(',');
    }

    return { columnCount: cells.length, delimiter, headerHash, dataTopology: topology };
};

export const findMatchingModel = (content: string, models: FileModel[]): FileModel | null => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length === 0) return null;

    // Gera fingerprint "na hora"
    const current = generateFingerprint(content);
    if (!current) return null;

    // Também gera hash simples da string do cabeçalho para comparação exata
    const rawHeader = lines[0].trim();

    return models.find(m => {
        if (!m.is_active) return false;

        // 1. Verifica Hash Exato de Cabeçalho (Mais confiável)
        // Precisamos reconstruir o header esperado baseando no delimitador do modelo
        // Mas como não temos o arquivo original do modelo, usamos o hash salvo
        if (m.fingerprint.headerHash === current.headerHash) return true;

        // 2. Verifica contagem de colunas + topologia
        if (m.fingerprint.columnCount === current.columnCount) {
             // Se o cabeçalho mudou mas a estrutura de dados (Topologia N,S,N) é igual, aceita
             if (m.fingerprint.dataTopology === current.dataTopology) return true;
        }

        return false;
    }) || null;
};

export const isModelSafeToApply = (content: string, model: FileModel): { safe: boolean; reason?: string } => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length === 0) return { safe: false, reason: "Arquivo vazio" };

    // Tenta detectar delimitador forçando a contagem de colunas do modelo
    const delimiter = detectDelimiter(lines[0], model.fingerprint.columnCount);
    const cols = lines[0].split(delimiter).length;

    if (cols !== model.fingerprint.columnCount) {
        return { safe: false, reason: `Divergência de colunas: esperado ${model.fingerprint.columnCount}, detectado ${cols}` };
    }

    return { safe: true };
};

const finalizeTransaction = (
    rawDate: string, 
    rawDesc: string, 
    rawAmount: string, 
    rawType: string | undefined,
    anchorYear: number, 
    index: number, 
    userKeywords: string[] = []
): Transaction | null => {
    const isoDate = DateResolver.resolveToISO(rawDate, anchorYear);
    const standardizedAmountStr = AmountResolver.clean(rawAmount);
    const numericAmount = parseFloat(standardizedAmountStr);

    // Validação Relaxada: Se tiver descrição e data, aceita mesmo que valor seja 0 (para debug)
    if (!isoDate && !rawDesc && isNaN(numericAmount)) {
        return null;
    }

    let cleanedName = NameResolver.clean(rawDesc, userKeywords);
    if (!cleanedName || cleanedName.trim().length === 0) {
        cleanedName = rawDesc.trim(); 
        if (!cleanedName) cleanedName = "Sem descrição"; 
    }

    return {
        id: `tx-norm-${index}-${Date.now()}`,
        date: isoDate || rawDate, 
        description: cleanedName,
        amount: isNaN(numericAmount) ? 0 : numericAmount,
        originalAmount: rawAmount,
        cleanedDescription: cleanedName,
        contributionType: rawType?.trim().toUpperCase()
    };
};

export const parseWithModel = (content: string, model: FileModel, userKeywords: string[] = []): Transaction[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    const { mapping, parsingRules } = model;
    const anchorYear = DateResolver.discoverAnchorYear(content);

    // DELIMITADOR DINÂMICO INTELIGENTE:
    // Usa a contagem de colunas salva no modelo para forçar a escolha do delimitador correto.
    const currentDelimiter = detectDelimiter(lines[0] || '', model.fingerprint.columnCount);

    const savedKeywords = parsingRules?.ignoredKeywords || [];
    const effectiveKeywords = Array.from(new Set([...savedKeywords, ...userKeywords]));

    const dataLines = lines.slice(mapping.skipRowsStart, mapping.skipRowsEnd ? lines.length - mapping.skipRowsEnd : undefined);

    return dataLines.map((line, i) => {
        const upperLine = line.toUpperCase();
        if (parsingRules?.rowFilters?.some(f => upperLine.includes(f.toUpperCase()))) return null;

        // IMPORTANTE: Remove aspas extras que CSVs às vezes colocam
        const cells = line.split(currentDelimiter).map(c => c.trim().replace(/^["']|["']$/g, ''));

        // Verifica se a linha tem colunas suficientes para o mapeamento
        const maxIndexNeeded = Math.max(mapping.dateColumnIndex, mapping.descriptionColumnIndex, mapping.amountColumnIndex);
        if (cells.length <= maxIndexNeeded) return null;

        const rawDate = cells[mapping.dateColumnIndex] || '';
        const rawDesc = cells[mapping.descriptionColumnIndex] || '';
        const rawAmount = cells[mapping.amountColumnIndex] || '';
        const rawType = mapping.typeColumnIndex !== undefined && mapping.typeColumnIndex !== null ? cells[mapping.typeColumnIndex] : undefined;

        return finalizeTransaction(rawDate, rawDesc, rawAmount, rawType, anchorYear, i, effectiveKeywords);
    }).filter((t): t is Transaction => t !== null);
};

export const parseBankStatement = (content: string, customIgnoreKeywords: string[] = [], contributionKeywords: string[] = DEFAULT_CONTRIBUTION_KEYWORDS): Transaction[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 1) return [];

    const delimiter = detectDelimiter(lines[0]);
    const parsedRows = lines.map(l => l.split(delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));
    const anchorYear = DateResolver.discoverAnchorYear(content);

    const dateIdx = DateResolver.identifyDateColumn(parsedRows);
    const amountIdx = AmountResolver.identifyAmountColumn(parsedRows, [dateIdx]);
    const nameIdx = NameResolver.identifyNameColumn(parsedRows, [dateIdx, amountIdx]);
    const typeIdx = identifyTypeColumn(parsedRows, contributionKeywords);

    return parsedRows.map((row, i) => {
        const rawType = typeIdx !== -1 ? row[typeIdx] : undefined;
        const rawDate = dateIdx !== -1 ? (row[dateIdx] || '') : ''; 
        const safeDate = rawDate || row[0];
        const safeName = row[nameIdx !== -1 ? nameIdx : 1] || '';
        const safeAmount = row[amountIdx !== -1 ? amountIdx : 2] || '0';

        return finalizeTransaction(safeDate, safeName, safeAmount, rawType, anchorYear, i, customIgnoreKeywords);
    }).filter((t): t is Transaction => t !== null);
};

export const normalizeString = (str: string, ignoreKeywords: string[] = []): string => {
    if (!str) return '';
    let cleaned = NameResolver.clean(str, ignoreKeywords);
    if (!cleaned || cleaned.trim().length === 0) cleaned = str;
    return NameResolver.normalize(cleaned).toLowerCase();
};

export const calculateNameSimilarity = (description: string, contributor: Contributor, ignoreKeywords: string[] = []): number => {
    const txNorm = normalizeString(description, ignoreKeywords);
    const contribNorm = contributor.normalizedName || normalizeString(contributor.name, ignoreKeywords);

    if (!txNorm || !contribNorm) return 0;

    const txTokens = txNorm.split(/\s+/).filter(t => t.length > 0);
    const contribTokens = contribNorm.split(/\s+/).filter(t => t.length > 0);

    if (txTokens.length === 0 || contribTokens.length === 0) return 0;

    const txSet = new Set(txTokens);
    const contribSet = new Set(contribTokens);
    const intersection = [...txSet].filter(w => contribSet.has(w)).length;
    return (2 * intersection) / (txSet.size + contribSet.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: any[],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: any[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    const allContributors = contributorFiles.flatMap(file => 
        file.contributors.map((c: any) => ({ ...c, church: file.church }))
    );

    const finalResults: MatchResult[] = [];

    transactions.forEach(tx => {
        if (NameResolver.isControlRow(tx.description)) return;

        const txDescNormalized = normalizeString(tx.description, customIgnoreKeywords);

        const learned = learnedAssociations.find(la => la.normalizedDescription === txDescNormalized);
        if (learned) {
            const matchedContrib = allContributors.find(c => 
                (normalizeString(c.name, customIgnoreKeywords) === learned.contributorNormalizedName) && 
                (c.church.id === learned.churchId)
            );
            if (matchedContrib) {
                finalResults.push({ 
                    transaction: tx, contributor: matchedContrib, status: 'IDENTIFICADO', 
                    church: matchedContrib.church, matchMethod: 'LEARNED', similarity: 100, 
                    contributorAmount: matchedContrib.amount,
                    contributionType: matchedContrib.contributionType || tx.contributionType
                });
                return;
            }
        }

        let bestMatch: any = null;
        let highestScore = 0;

        allContributors.forEach(contrib => {
            if (options.dayTolerance !== undefined && contrib.date && tx.date) {
                const tDate = parseDate(tx.date);
                const cDate = parseDate(contrib.date);
                if (tDate && cDate) {
                    const diffDays = Math.ceil(Math.abs(tDate.getTime() - cDate.getTime()) / (1000 * 3600 * 24));
                    if (diffDays > options.dayTolerance) return;
                }
            }

            const score = calculateNameSimilarity(tx.description, contrib, customIgnoreKeywords);
            if (score >= options.similarityThreshold && score > highestScore) {
                highestScore = score;
                bestMatch = contrib;
            }
        });

        if (bestMatch) {
            finalResults.push({ 
                transaction: tx, contributor: bestMatch, status: 'IDENTIFICADO', 
                church: bestMatch.church, similarity: highestScore, 
                matchMethod: 'AUTOMATIC', contributorAmount: bestMatch.amount,
                contributionType: bestMatch.contributionType || tx.contributionType
            });
        } else {
            finalResults.push({ 
                transaction: tx, contributor: null, status: 'NÃO IDENTIFICADO', 
                church: PLACEHOLDER_CHURCH,
                contributionType: tx.contributionType
            });
        }
    });

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): Record<string, MatchResult[]> => {
    const grouped: Record<string, MatchResult[]> = {};
    results.forEach(r => {
        const key = r.church?.id || 'unidentified';
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

export const parseDate = (dateString: string): Date | null => {
    if (!dateString) return null;
    const clean = dateString.trim().replace(/\//g, '-');
    if (/^\d{4}-\d{2}-\d{2}$/.test(clean)) return new Date(clean);

    const parts = clean.split('-');
    if (parts.length === 3) {
        if (parts[0].length === 4) return new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        else return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    }
    return null;
};

export const parseContributors = (content: string, ignoreKeywords: string[] = [], contributionKeywords: string[] = DEFAULT_CONTRIBUTION_KEYWORDS): Contributor[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 1) return [];

    const delimiter = detectDelimiter(lines[0]);
    const parsedRows = lines.map(l => l.split(delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));
    const anchorYear = DateResolver.discoverAnchorYear(content);

    const dateIdx = DateResolver.identifyDateColumn(parsedRows);
    const amountIdx = AmountResolver.identifyAmountColumn(parsedRows, [dateIdx]);
    const nameIdx = NameResolver.identifyNameColumn(parsedRows, [dateIdx, amountIdx]);
    const typeIdx = identifyTypeColumn(parsedRows, contributionKeywords);

    return parsedRows.map((row, i): Contributor | null => {
        const rawDate = dateIdx !== -1 ? (row[dateIdx] || '') : '';
        const isoDate = rawDate ? DateResolver.resolveToISO(rawDate, anchorYear) : undefined;

        const rawName = nameIdx !== -1 ? (row[nameIdx] || '') : (row[0] || '');
        const rawAmount = amountIdx !== -1 ? (row[amountIdx] || '') : '0.00';
        const rawType = typeIdx !== -1 ? row[typeIdx] : undefined;

        const standardizedAmountStr = AmountResolver.clean(rawAmount);
        const numericAmount = parseFloat(standardizedAmountStr);

        let cleanedName = NameResolver.clean(rawName, ignoreKeywords);
        if (!cleanedName || cleanedName.trim().length === 0) cleanedName = rawName.trim();

        if (!cleanedName || isNaN(numericAmount)) {
            return null;
        }

        return {
            name: cleanedName,
            cleanedName: cleanedName,
            normalizedName: normalizeString(rawName, ignoreKeywords),
            amount: numericAmount,
            date: isoDate,
            originalAmount: rawAmount,
            contributionType: rawType?.trim().toUpperCase()
        };
    }).filter((c): c is Contributor => c !== null);
};

export const cleanTransactionDescriptionForDisplay = (description: string, ignoreKeywords: string[] = []): string => {
    const cleaned = NameResolver.clean(description, ignoreKeywords);
    if (!cleaned || cleaned.trim().length === 0) return description;
    return cleaned;
};

export const formatIncomeDescription = (description: string, ignoreKeywords: string[] = []): string => {
    return cleanTransactionDescriptionForDisplay(description, ignoreKeywords);
};

export const formatExpenseDescription = (description: string): string => {
    return NameResolver.clean(description);
};

export const filterTransactionByUniversalQuery = (tx: Transaction, query: string): boolean => {
    if (!query || !query.trim()) return true;
    const terms = query.toLowerCase().split(/\s+/).filter(t => t.length > 0);
    const dateStr = tx.date.toLowerCase();
    const descStr = (tx.cleanedDescription || tx.description || '').toLowerCase();
    const typeStr = (tx.contributionType || '').toLowerCase();
    const amountStr = tx.amount.toFixed(2).replace('.', ',');
    const amountStrDot = tx.amount.toFixed(2);

    return terms.every(term => 
        dateStr.includes(term) || 
        descStr.includes(term) || 
        typeStr.includes(term) ||
        amountStr.includes(term) || 
        amountStrDot.includes(term)
    );
};

export const filterByUniversalQuery = (result: MatchResult, query: string): boolean => {
    if (!query || !query.trim()) return true;
    const terms = query.toLowerCase().split(/\s+/).filter(t => t.length > 0);

    const tx = result.transaction;
    const dateStr = (result.contributor?.date || tx.date).toLowerCase();
    const descStr = (tx.cleanedDescription || tx.description || '').toLowerCase();
    const contribName = (result.contributor?.name || '').toLowerCase();
    const churchName = (result.church?.name || '').toLowerCase();
    const typeStr = (result.contributionType || '').toLowerCase();

    const amount = result.contributorAmount ?? tx.amount;
    const amountStr = amount.toFixed(2).replace('.', ',');
    const amountStrDot = amount.toFixed(2);

    return terms.every(term => 
        dateStr.includes(term) || 
        descStr.includes(term) || 
        contribName.includes(term) || 
        churchName.includes(term) || 
        typeStr.includes(term) ||
        amountStr.includes(term) || 
        amountStrDot.includes(term)
    );
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    findMatchingModel,
    PLACEHOLDER_CHURCH,
    parseWithModel,
    isModelSafeToApply,
    normalizeString,
    parseBankStatement,
    parseContributors
} from '../services/processingService';

interface UseReconciliationProps {
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>('identificapix-statement-v7', null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>('identificapix-contributors-v6', [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>('identificapix-results-v6', [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>('identificapix-report-preview-v6', null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>('identificapix-has-session-v6', false, false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // STRICT MODE: Primeiro busca um modelo exato
            const matchedModel = findMatchingModel(content, fileModels);

            if (matchedModel && isModelSafeToApply(content, matchedModel).safe) {
                // Se achou modelo seguro, processa
                const transactions = parseWithModel(content, matchedModel, customIgnoreKeywords);

                if (transactions.length > 0) {
                    setBankStatementFile({ 
                        bankId, 
                        content, 
                        fileName, 
                        rawFile,
                        processedTransactions: transactions 
                    });
                    showToast(`Extrato carregado (${matchedModel.name}).`, 'success');
                } else {
                    // Modelo existe mas não gerou dados (falha de regras), força lab
                    setPendingTraining({ content, fileName, type: 'statement', entityId: bankId, rawFile });
                    showToast("Modelo não capturou dados. Verifique no Laboratório.", "error");
                }
            } else {
                // Se NÃO tem modelo ou não é seguro: FORÇA O LABORATÓRIO
                // Não fazemos fallback para parse genérico aqui para garantir integridade
                setPendingTraining({ content, fileName, type: 'statement', entityId: bankId, rawFile });
                showToast("Arquivo novo detectado. Configure o modelo.", "success");
            }
        } catch (e) {
            showToast("Erro ao ler o arquivo.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, setBankStatementFile, showToast, setIsLoading, customIgnoreKeywords]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // STRICT MODE: Igual ao extrato
            const matchedModel = findMatchingModel(content, fileModels);

            if (matchedModel && isModelSafeToApply(content, matchedModel).safe) {
                const transactions = parseWithModel(content, matchedModel, customIgnoreKeywords);
                if (transactions.length > 0) {
                    const contributors = transactions.map(t => ({
                        name: t.description,
                        cleanedName: t.cleanedDescription,
                        normalizedName: normalizeString(t.description, customIgnoreKeywords),
                        amount: t.amount,
                        date: t.date,
                        originalAmount: t.originalAmount,
                        contributionType: t.contributionType
                    }));

                    setContributorFiles(prev => {
                        const other = prev.filter(f => f.churchId !== churchId);
                        return [...other, { churchId, content, fileName, contributors }];
                    });
                    showToast(`Lista carregada (${matchedModel.name}).`, 'success');
                } else {
                    setPendingTraining({ content, fileName, type: 'contributor', entityId: churchId, rawFile });
                    showToast("Modelo não capturou dados. Verifique no Laboratório.", "error");
                }
            } else {
                setPendingTraining({ content, fileName, type: 'contributor', entityId: churchId, rawFile });
                showToast("Arquivo novo detectado. Configure o modelo.", "success");
            }
        } catch (e) {
            showToast("Erro ao ler o arquivo.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, customIgnoreKeywords, setContributorFiles, showToast, setIsLoading]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo!", "success");
        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, customIgnoreKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes salva!", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, customIgnoreKeywords, setBankStatementFile, setContributorFiles, showToast]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile) return;
        setIsLoading(true);

        try {
            // 1. REPROCESSAMENTO AUTOMÁTICO DO EXTRATO
            const stmtModel = findMatchingModel(bankStatementFile.content, fileModels);
            let activeTransactions: Transaction[] = [];

            if (stmtModel) {
                console.log(`Aplicando modelo salvo '${stmtModel.name}' ao extrato...`);
                activeTransactions = parseWithModel(bankStatementFile.content, stmtModel, customIgnoreKeywords);
            } else {
                // Fallback apenas se já tiver dados em memória processados via Lab
                // Se não tiver, é erro (usuário burlou o Lab)
                if (bankStatementFile.processedTransactions && bankStatementFile.processedTransactions.length > 0) {
                    activeTransactions = bankStatementFile.processedTransactions;
                } else {
                    // Último recurso: parser genérico (mas deve ser raro pois o upload barra)
                    activeTransactions = parseBankStatement(bankStatementFile.content, customIgnoreKeywords, contributionKeywords);
                }
            }

            if (activeTransactions.length === 0) {
                throw new Error("O extrato não gerou transações válidas. Verifique o modelo no Laboratório.");
            }

            // Atualiza o estado global para refletir o processamento mais recente
            setBankStatementFile(prev => prev ? { ...prev, processedTransactions: activeTransactions } : null);

            // Filtros de Tipo (Income/Expenses)
            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. REPROCESSAMENTO AUTOMÁTICO DAS LISTAS DE CONTRIBUINTES
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;

                const listModel = findMatchingModel(cf.content, fileModels);
                let currentContributors: Contributor[] = [];

                if (listModel) {
                    console.log(`Aplicando modelo salvo '${listModel.name}' à lista de ${church.name}...`);
                    const txs = parseWithModel(cf.content, listModel, customIgnoreKeywords);
                    currentContributors = txs.map(t => ({
                        name: t.description,
                        cleanedName: t.cleanedDescription,
                        normalizedName: normalizeString(t.description, customIgnoreKeywords),
                        amount: t.amount,
                        date: t.date,
                        originalAmount: t.originalAmount,
                        contributionType: t.contributionType
                    }));
                } else {
                    currentContributors = cf.contributors || [];
                }

                return {
                    church,
                    contributors: currentContributors
                };
            });

            // 3. EXECUTAR O MATCHING
            const results = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                customIgnoreKeywords
            );

            setMatchResults(results);
            setReportPreviewData({
                income: groupResultsByChurch(results.filter(r => r.transaction.amount > 0)),
                expenses: { 'all_expenses_group': results.filter(r => r.transaction.amount < 0) }
            });
            setHasActiveSession(true);
            setActiveView('reports');
            showToast("Conciliação finalizada!", 'success');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, contributorFiles, churches, fileModels, similarityLevel, dayTolerance, customIgnoreKeywords, contributionKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses') => {
        setMatchResults(prev => prev.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r));
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            Object.keys(targetGroup).forEach(key => {
                targetGroup[key] = targetGroup[key].map((r: MatchResult) => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
            });

            if (reportType === 'income') {
                const currentChurchId = updatedRow.church.id || 'unidentified';
                Object.keys(newPreview.income).forEach(key => {
                    newPreview.income[key] = newPreview.income[key].filter((r: MatchResult) => r.transaction.id !== updatedRow.transaction.id);
                });
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
